// Parse commit messages for [BER-XX] done: pattern (multiline-freundlich)
const items = $input.all();
const results = [];
const regex = /\[BER-(\d+)\]\s*done:?\s*([\s\S]*)/i;

for (const item of items) {
  const commits = item.json.body?.commits || item.json.commits || [];

  for (const commit of commits) {
    const message = commit.message || '';
    const match = message.match(regex);

    if (match) {
      const descRaw = (match[2] || '').trim();
      const description = descRaw.split(/\r?\n/)[0].trim();
      results.push({
        json: {
          issueNumber: parseInt(match[1], 10),
          issueId: 'BER-' + match[1],
          description,
          commitSha: (commit.id || commit.sha || '').substring(0, 8),
          commitUrl: commit.url || '',
          author: commit.author?.name || commit.author?.username || 'unknown',
          timestamp: commit.timestamp || new Date().toISOString(),
          matched: true
        }
      });
    }
  }
}

if (results.length === 0) {
  results.push({ json: { matched: false } });
}

return results;

