const parse = $('Commit-Message parsen').item.json;
const lookup = $('Linear Issue Lookup').item.json;
const linearDone = $('Linear auf Done setzen').item.json;
const threema = $('Threema Benachrichtigung').item.json;
const notion = $('Notion PARA-Hub Kommentar').item.json;

const linearUuid = lookup?.data?.issues?.nodes?.[0]?.id;
const linearLookupOk = !!linearUuid;
const linearUpdateOk = linearDone?.data?.issueUpdate?.success === true;
const notionOk = !!(notion?.id || notion?.object === 'comment');

return {
  json: {
    issueId: parse.issueId,
    beschreibung: parse.description,
    linear_lookup_ok: linearLookupOk,
    linear_update_ok: linearUpdateOk,
    threema_gesendet: !threema?.error,
    notion_kommentar_ok: notionOk,
    nachricht: `Rückkanal für ${parse.issueId}: Linear ${linearUpdateOk ? 'Done' : 'nicht gesetzt'}, Threema/Notion siehe Flags.`
  }
};
